    # 使用 validators 库进行基本的 URL 格式验证
    if not validators.url(url):
        return False
    # 允许的域名白名单
    allowed_domains = ['example.com', 'www.example.com']
    parsed_url = requests.utils.urlparse(url)
    # 检查域名是否在白名单中
