def fetch_url_content(url):
    # Validate the URL scheme to prevent SSRF
    parsed_url = urlparse(url)
    if parsed_url.scheme not in ['http', 'https']:
        raise ValueError('Invalid URL scheme')

    # Attempt to prevent local host access by checking netloc
    if 'localhost' in parsed_url.netloc or '127.0.0.1' in parsed_url.netloc:
        raise ValueError('Access to localhost is denied')

    # Use a timeout to avoid hanging requests
    try:
        response = requests.get(url, timeout=5, allow_redirects=False)
    except requests.exceptions.RequestException as e:
        return f'Error fetching URL: {e}'

    # Follow only one redirect to avoid infinite loops
    if response.status_code == 302 and 'Location' in response.headers:
        redirect_url = response.headers['Location']
        parsed_redirect_url = urlparse(redirect_url)

        # Check if the redirect URL is within the same domain
        if parsed_url.netloc == parsed_redirect_url.netloc:
            try:
                response = requests.get(redirect_url, timeout=5)
            except requests.exceptions.RequestException as e:
                return f'Error fetching redirected URL: {e}'

    return response.text

