import logging
from flask import Flask, jsonify, request

app = Flask(__name__)
logging.basicConfig(level=logging.DEBUG)

def log_request_info(func):
    def wrapper(*args, **kwargs):
        app.logger.debug(f'Request: {request.method} {request.url} with headers {request.headers}')
        response = func(*args, **kwargs)
        app.logger.debug(f'Response: {response.status_code} with data {response.get_data()}')
        return response
    return wrapper

